   301	    private Map<String, String> parseTags(JsonNode tagsNode) {
   302	        if (!tagsNode.isArray()) return null;
   303	        Map<String, String> tags = new HashMap<>();
   304	        for (JsonNode tagNode : tagsNode) {
   305	            String key = tagNode.path("Key").asText();
   306	            String value = tagNode.path("Value").asText(null);
   307	            tags.put(key, value);
   308	        }
   309	        return tags;
