   312	    private ValidationMethod parseValidationMethod(String method) {
   313	        if (method == null) return ValidationMethod.DNS;
   314	        try {
   315	            return ValidationMethod.valueOf(method.toUpperCase());
   316	        } catch (IllegalArgumentException e) {
   317	            throw new io.github.hectorvent.floci.core.common.AwsException(
   318	                "ValidationException",
   319	                "Invalid validation method: " + method + ". Must be DNS or EMAIL.",
   320	                400);
   321	        }
   322	    }
