        }
        node.set("SubjectAlternativeNames", sans);
        node.set("SubjectAlternativeNameSummaries", sans.deepCopy());
        node.put("HasAdditionalSubjectAlternativeNames", false);

        node.put("Status", cert.getStatus().name());
