        }
        if (cert.getSignatureAlgorithm() != null) {
            node.put("SignatureAlgorithm", cert.getSignatureAlgorithm());
        }
        if (cert.getSerial() != null) {
            node.put("Serial", cert.getSerial());
        }
        if (cert.getSubject() != null) {
